sql:
SELECT COUNT(*) 
FROM journal_articles
WHERE journal_id = 1;

SELECT publication_year, COUNT(volume_id) AS VolumeCount
FROM journal_volumes
GROUP BY publication_year;

SELECT journals.journal_id, subscriptions.subscription_id
FROM journals
LEFT JOIN subscriptions ON journals.journal_id = subscriptions.journal_id;

SELECT journal_id, COUNT(*) AS number_of_articles
FROM journal_articles 
GROUP BY journal_id;

SELECT COUNT(article_id) AS total_articles
FROM journal_articles
WHERE journal_id = 1;

SELECT journals.journal_id, journals.title, publishers.publisher_name
FROM journals
LEFT JOIN publishers ON journals.publisher = publishers.publisher_name;

SELECT journals.title, publishers.publisher_name, publishers.contact_email
FROM journals
JOIN publishers ON journals.publisher = publishers.publisher_name;

SELECT journals.title, publishers.publisher_name
FROM journals 
INNER JOIN publishers ON journals.publisher = publishers.publisher_name;
